{
  "$schema": "https://unpkg.com/knip@5/schema.json",
  "workspaces": {
    ".": {
      "entry": ["scripts/*.{js,ts,sh}"],
      "ignoreDependencies": ["turbo-ignore", "@biomejs/biome"]
    },
    "apps/app": {
      "entry": ["src/app/**/*.{ts,tsx}"],
      "project": ["src/**/*.{ts,tsx}"],
      "ignoreDependencies": ["@vendor/lib", "@vitest/expect", "zustand"]
    },
    "apps/www": {
      "entry": ["src/app/**/*.{ts,tsx}"],
      "project": ["src/**/*.{ts,tsx}"],
      "ignoreDependencies": ["jiti"]
    },
    "apps/platform": {
      "entry": ["src/app/**/*.{ts,tsx}"],
      "project": ["src/**/*.{ts,tsx}"]
    },
    "api/*": {
      "project": ["src/**/*.ts"]
    },
    "core/*": {
      "project": ["src/**/*.ts"]
    },
    "core/ai-sdk": {
      "entry": ["src/core/memory/adapters/*.ts", "src/core/test-utils/*.ts"],
      "project": ["src/**/*.ts"]
    },
    "db/*": {
      "entry": ["src/drizzle.config.ts"],
      "project": ["src/**/*.ts"]
    },
    "packages/*": {
      "project": ["src/**/*.{ts,tsx}"]
    },
    "packages/app-ai": {
      "entry": ["src/org-*.ts"],
      "project": ["src/**/*.ts"]
    },
    "packages/app-test-data": {
      "entry": ["src/cli/**/*.ts"],
      "project": ["src/**/*.ts"]
    },
    "packages/app-trpc": {
      "project": ["src/**/*.{ts,tsx}"]
    },
    "packages/og": {
      "project": ["src/**/*.{ts,tsx}"],
      "ignoreDependencies": ["react", "@types/react"]
    },
    "packages/app-upstash-realtime": {
      "ignoreDependencies": ["@types/react"]
    },
    "packages/ui": {
      "project": ["src/**/*.{ts,tsx}"],
      "ignoreDependencies": ["@turbo/gen"]
    },
    "vendor/*": {
      "project": ["src/**/*.ts"],
      "drizzle": false
    },
    "vendor/aeo": {
      "project": ["*.ts"],
      "drizzle": false
    },
    "vendor/analytics": {
      "project": ["src/**/*.{ts,tsx}"],
      "drizzle": false
    },
    "vendor/seo": {
      "project": ["src/**/*.{ts,tsx}"],
      "drizzle": false
    },
    "vendor/inngest": {
      "drizzle": false
    },
    "vendor/next": {
      "project": ["src/**/*.ts"],
      "drizzle": false
    },
    "internal/typescript": {
      "entry": ["base.json"]
    },
    "internal/vitest-config": {
      "entry": ["vitest.shared.ts"]
    }
  },
  "ignore": [".agents/**", ".claude/**"],
  "ignoreWorkspaces": ["packages/app-remotion"],
  "ignoreDependencies": [
    "tailwindcss",
    "@tailwindcss/postcss",
    "@tailwindcss/typography",
    "postcss",
    "autoprefixer",
    "import-in-the-middle",
    "require-in-the-middle",
    "@vitest/coverage-v8"
  ]
}
